import json

# Access the result from the previous query
businesses = var_functions.query_db:0

# Filter businesses located in Indianapolis, Indiana
indianapolis_businesses = []
for business in businesses:
    description = business.get('description', '')
    if 'Indianapolis, IN' in description or 'Indianapolis, Indiana' in description:
        indianapolis_businesses.append(business)

# Extract business IDs and get the numeric part for mapping
business_id_map = {}
for business in indianapolis_businesses:
    business_id = business['business_id']  # e.g., "businessid_52"
    numeric_id = business_id.replace('businessid_', '')  # e.g., "52"
    business_id_map[numeric_id] = business

print('__RESULT__:')
print(json.dumps({
    'indianapolis_count': len(indianapolis_businesses),
    'business_id_map_keys': list(business_id_map.keys())[:10]  # Show first 10 for debugging
}))

